import { useState } from "react";

function StatCard({ title, value, color }) {
  return (
    <div
      style={{
        background: "#313244",
        padding: "20px",
        borderRadius: "8px",
        minWidth: "150px",
        borderTop: `4px solid `,
        borderTopColor: color,
      }}
    >
      <h3 style={{ margin: "0 0 10px 0", color: "#a6adc8", fontSize: "14px" }}>
        {title}
      </h3>
      <p
        style={{
          margin: 0,
          fontSize: "28px",
          fontWeight: "bold",
          color: "#cdd6f4",
        }}
      >
        {value}
      </p>
    </div>
  );
}

export default function App() {
  const [cpu, setCpu] = useState(12);
  const [ram, setRam] = useState(6.2);

  function refreshStats() {
    const newCpu = Math.floor(Math.random() * 100);
    const newRam = (Math.random() * 15 + 1).toFixed(1);
    setCpu(newCpu);
    setRam(newRam);
  }

  return (
    <div
      style={{
        background: "#1e1e2e",
        color: "#cdd6f4",
        padding: "40px",
        minHeight: "100vh",
        fontFamily: "monospace",
      }}
    >
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <h2>$ htop - system monitor</h2>
        <button
          onClick={refreshStats}
          style={{
            background: "#89b4fa",
            color: "#1e1e2e",
            border: "none",
            padding: "10px 20px",
            borderRadius: "5px",
            cursor: "pointer",
            fontWeight: "bold",
          }}
        >
          🔄 Оновити дані
        </button>
      </div>

      <div
        style={{
          display: "flex",
          gap: "20px",
          flexWrap: "wrap",
          marginTop: "30px",
        }}
      >
        {/* 2. ТУТ ТВІЙ КОД: 
            Замість value="12%" передай сюди свій стан cpu.
            Щоб додати знак відсотка, використай шаблонні рядки: value={`${cpu}%`}
        */}
        <StatCard title="CPU usage" value={cpu} color="#f38ba8" />

        {/* Зроби те саме для RAM, але додай літеру "G" (Гігабайти) */}
        <StatCard title="RAM usage" value={`${ram} g`} color="#a6e3a1" />

        {/* Диск поки залишаємо статичним, він рідко скаче */}
        <StatCard title="Disk usage" value="255/420G" color="#89b4fa" />
      </div>
    </div>
  );
}
